        for (const d of uniqueNums) {
            // If d divides originalVal, it is a candidate for replacement.
            if (originalVal % d === 0) {
                // Since uniqueNums is sorted ascendingly, the first d that divides originalVal
                // is the smallest such divisor in the original set.
                smallestDivisor = d;
                break; 
            }
        }
        minSum += smallestDivisor;
    }

    return minSum;
